local limit = 100
local window = 60
local dict_name = "rate_limit"

local function rate_limit(key)
    local dict = ngx.shared[dict_name]
    local current = dict:get(key)
    
    if current == nil then
        dict:set(key, 1, window)
        return false
    end
    
    if current >= limit then
        return true
    end
    
    dict:set(key, current + 1, window)
    return false
end

